package com.chaobo.scm.supplier.infrastructure.mq;

import com.chaobo.scm.supplier.application.contract.*;import jakarta.annotation.PreDestroy;import org.apache.rocketmq.client.apis.*;import org.apache.rocketmq.client.apis.consumer.*;import org.apache.rocketmq.client.apis.message.MessageView;import org.slf4j.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;import org.springframework.stereotype.Component;import tools.jackson.databind.ObjectMapper;import java.nio.ByteBuffer;import java.util.*;
@Component @ConditionalOnProperty(name="scm.rocketmq.contract-approval-consumer.enabled",havingValue="true") public class RocketMqContractApprovalConsumer {private static final Logger log=LoggerFactory.getLogger(RocketMqContractApprovalConsumer.class);private final PushConsumer consumer;private final ContractApprovalEventConsumerApplicationService service;private final ObjectMapper json;public RocketMqContractApprovalConsumer(ContractApprovalEventConsumerApplicationService service,ObjectMapper json,@Value("${scm.rocketmq.endpoints}")String endpoints,@Value("${scm.rocketmq.contract-approval-consumer.topic}")String topic,@Value("${scm.rocketmq.contract-approval-consumer.group}")String group)throws Exception{this.service=service;this.json=json;var provider=ClientServiceProvider.loadService();consumer=provider.newPushConsumerBuilder().setClientConfiguration(ClientConfiguration.newBuilder().setEndpoints(endpoints).build()).setConsumerGroup(group).setSubscriptionExpressions(Map.of(topic,FilterExpression.SUB_ALL)).setConsumptionThreadCount(4).setMessageListener(this::consume).build();}private ConsumeResult consume(MessageView message){try{service.consume(event(message));return ConsumeResult.SUCCESS;}catch(Exception ex){log.warn("合同审批事件消费失败，等待RocketMQ重试，messageId={}",message.getMessageId(),ex);return ConsumeResult.FAILURE;}}@SuppressWarnings("unchecked")private ContractApprovalEvent event(MessageView message)throws Exception{var buffer=message.getBody().asReadOnlyBuffer();byte[] bytes=new byte[buffer.remaining()];buffer.get(bytes);Map<String,Object> envelope=json.readValue(bytes,Map.class);Map<String,Object> data=envelope.get("data")instanceof Map<?,?> raw?(Map<String,Object>)raw:envelope;String code=text(envelope,"eventCode",message.getMessageId().toString());String type=text(envelope,"eventType",message.getTag().orElse("ContractApprovalCompleted"));return new ContractApprovalEvent(code,text(envelope,"sourceSystem","IAM"),type,number(data.get("contractId")),Math.toIntExact(number(data.get("contractVersion"))),Boolean.parseBoolean(String.valueOf(data.get("approved"))),text(data,"comment",null));}private static String text(Map<String,Object> data,String key,String fallback){var v=data.get(key);return v==null?fallback:String.valueOf(v);}private static long number(Object value){if(value instanceof Number n)return n.longValue();return Long.parseLong(String.valueOf(value));}@PreDestroy public void close()throws Exception{consumer.close();}}
